static bool simplifyAndWithKnownBits(Instruction *I, DemandedBits &DB) {
  if (I->getOpcode() != Instruction::And)
    return false;

  Value *Op0 = I->getOperand(0);
  Value *Op1 = I->getOperand(1);
  ConstantInt *C = dyn_cast<ConstantInt>(Op1);
  if (!C)
