  // through another AND if the outer AND only demands bits that are already
  // covered by the inner constant.
  uint64_t Mask = C->getZExtValue();
  if (Mask == 0)
    return false;

  // Check if the first operand is another AND with a constant.
  Instruction *OuterAnd = dyn_cast<Instruction>(Op0);
